def diffWaysToCompute(self, expression: str) -> List[int]:
    result = []
    stack = []
    for char in expression:
        if char == '+' or char == '-':
            num1, num2 = stack.pop(), stack.pop()
            if char == '+':
                result.append(num1 + num2)
            elif char == '-':
                result.append(num1 - num2)
        else:
            stack.append(int(char))
    return result

